// pages/index.js – Ana səhifə
function Home() {
  return <h1>Xoş gəldiniz Next.js-ə!</h1>;
}

export default Home;

// pages/about.js – /about səhifəsi
function About() {
  return <h1>Haqqımızda</h1>;
}

export default About;

console.log('Next.js routing nümunəsi');

function Blog({ posts }) {
  return (
    <ul>
      {posts.map(post => <li key={post.id}>{post.title}</li>)}
    </ul>
  );
}

export async function getStaticProps() {
  // Mock data
  const posts = [{ id: 1, title: 'Next.js Öyrən' }];
  return { props: { posts } };
}

export default Blog;

console.log('getStaticProps ilə SSG nümunəsi');

function User({ user }) {
  return <p>İstifadəçi: {user.name}</p>;
}

export async function getServerSideProps() {
  // Mock data
  const user = { name: 'Aysel' };
  return { props: { user } };
}

export default User;

console.log('getServerSideProps ilə SSR nümunəsi');

// app/page.js – Ana səhifə
export default function Home() {
  return <h1>Next.js App Directory</h1>;
}

// app/about/page.js – /about
export default function About() {
  return <h1>Haqqımızda</h1>;
}

console.log('App Directory nümunəsi');

